import{_ as c,c as d,j as t,o as l}from"./index-CudOUriJ.js";const i={},v={class:"about"};function b(s,a){return l(),d("div",v,a[0]||(a[0]=[t('<div class="container" data-v-dbc7aca9><h2 data-v-dbc7aca9>О компании</h2><div class="about-content" data-v-dbc7aca9><div class="about-text" data-v-dbc7aca9><h3 data-v-dbc7aca9>ООО &quot;Квадрат&quot;</h3><p data-v-dbc7aca9><strong data-v-dbc7aca9>Первая компания в Сибири по ремонту и обработке поддонов</strong></p><p data-v-dbc7aca9>Мы специализируемся на всех видах работ с поддонами более 10 лет. Наша компания была основана с целью предоставления качественных услуг по ремонту, обработке и восстановлению поддонов для предприятий Сибирского региона.</p><h4 data-v-dbc7aca9>Ключевые услуги:</h4><ul class="services-list" data-v-dbc7aca9><li data-v-dbc7aca9><strong data-v-dbc7aca9>1. ОБРАБОТКА И СОРТИРОВКА</strong><ul data-v-dbc7aca9><li data-v-dbc7aca9>Приёмка партий любой сложности и объёма.</li><li data-v-dbc7aca9>Экспресс-сортировка на месте: исправные, под ремонт, брак.</li><li data-v-dbc7aca9>Очистка от загрязнений (пыль, грязь, остатки продукции).</li></ul></li><li data-v-dbc7aca9><strong data-v-dbc7aca9>2. РЕМОНТ И ВОССТАНОВЛЕНИЕ (ПЕРЕБОРКА)</strong><ul data-v-dbc7aca9><li data-v-dbc7aca9>Глубокий ремонт: Замена настилов, брусков, усиление углов.</li><li data-v-dbc7aca9>Экспресс-ремонт: Устранение мелких повреждений, забивка торчащих гвоздей.</li><li data-v-dbc7aca9>Восстановление «из брака»: Разборка непригодных паллет и сборка из годных компонентов новых.</li><li data-v-dbc7aca9>Используем профессиональный пневмоинструмент и станки.</li></ul></li><li data-v-dbc7aca9><strong data-v-dbc7aca9>3. САНИТАРНАЯ ОБРАБОТКА И СЕРТИФИКАЦИЯ</strong><ul data-v-dbc7aca9><li data-v-dbc7aca9>Термообработка (НТ) для экспортных паллет со стандартом ISPM 15.</li><li data-v-dbc7aca9>Нанесение маркировки IPPC.</li><li data-v-dbc7aca9>Промышленная мойка паллет.</li></ul></li><li data-v-dbc7aca9><strong data-v-dbc7aca9>4. ЛОГИСТИКА И ОБРАЩЕНИЕ</strong><ul data-v-dbc7aca9><li data-v-dbc7aca9>Загрузка/выгрузка паллет на вашем складе или на нашей площадке.</li><li data-v-dbc7aca9>Доставка исправных паллет «под заказ» к вашей производственной линии.</li><li data-v-dbc7aca9>Вывоз битых и грязных поддонов.</li><li data-v-dbc7aca9>Ответственное хранение и учёт вашего паллетного фонда.</li></ul></li><li data-v-dbc7aca9><strong data-v-dbc7aca9>5. КОНСАЛТИНГ И ПУЛИНГ</strong><ul data-v-dbc7aca9><li data-v-dbc7aca9>Анализ оборачиваемости и оптимизация затрат на тару.</li><li data-v-dbc7aca9>Организация услуг паллет-пулинга (аренды оборотных паллет) через партнёров.</li><li data-v-dbc7aca9>Утилизация непригодных паллет с выдачей актов.</li></ul></li></ul><h5 data-v-dbc7aca9>Наши преимущества:</h5><ul data-v-dbc7aca9><li data-v-dbc7aca9>«Под ключ»: От приёмки грязной тары до выдачи сертифицированных паллет.</li><li data-v-dbc7aca9>Скорость: Чёткие сроки благодаря отлаженному процессу.</li><li data-v-dbc7aca9>Экономия: Стоимость восстановления в 2-3 раза ниже покупки новой паллеты.</li><li data-v-dbc7aca9>Безопасность: Все восстановленные паллеты проходят контроль на прочность и соответствие ГОСТ/евростандартам.</li><li data-v-dbc7aca9>Прозрачность: Поэтапный отчёт и фотофиксация при необходимости.</li><li data-v-dbc7aca9>Современное оборудование, опытные специалисты, качественные материалы и гарантия на все виды работ</li></ul></div></div></div>',1)]))}const n=c(i,[["render",b],["__scopeId","data-v-dbc7aca9"]]);export{n as default};
